        function setupNavDots() {
            const dots = ['home', 'prodotti', 'marchi', 'promozioni', 'perche', 'orari'];
            const els = document.querySelectorAll('.ndot');
            els.forEach((d, i) => d.addEventListener('click', () => {
                const t = document.getElementById(dots[i]);
                if (t) t.scrollIntoView({
                    behavior: 'smooth'
                });
            }));
            const sections = dots.map(id => document.getElementById(id)).filter(Boolean);
            sections.forEach(s => {
                new IntersectionObserver(entries => {
                    entries.forEach(e => {
                        if (!e.isIntersecting) return;
                        const i = dots.indexOf(e.target.id);
                        els.forEach((d, j) => d.classList.toggle('active', j === i));
                    });
                }, {
                    threshold: .35
                }).observe(s);
            });
        }

