        /* â•â• TILT â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â• */
        function setupTilt() {
            function tilt(el, intensity) {
                const shine = document.createElement('div');
                shine.style.cssText = 'position:absolute;inset:0;pointer-events:none;opacity:0;transition:opacity .3s;border-radius:inherit';
                el.appendChild(shine);
                el.addEventListener('mousemove', e => {
                    const r = el.getBoundingClientRect(),
                        dx = (e.clientX - r.left - r.width / 2) / (r.width / 2),
                        dy = (e.clientY - r.top - r.height / 2) / (r.height / 2);
                    gsap.to(el, {
                        rotateX: -dy * intensity,
                        rotateY: dx * intensity,
                        transformPerspective: 800,
                        duration: .3,
                        ease: 'power2.out'
                    });
                    const px = ((e.clientX - r.left) / r.width) * 100,
                        py = ((e.clientY - r.top) / r.height) * 100;
                    shine.style.background = `radial-gradient(circle at ${px}% ${py}%,rgba(255,255,255,.07),transparent 58%)`;
                    shine.style.opacity = '1';
                });
                el.addEventListener('mouseleave', () => {
                    gsap.to(el, {
                        rotateX: 0,
                        rotateY: 0,
                        duration: .6,
                        ease: 'elastic.out(1,.5)'
                    });
                    shine.style.opacity = '0';
                });
            }
            document.querySelectorAll('.pc').forEach(el => tilt(el, 9));
            document.querySelectorAll('.lc').forEach(el => tilt(el, 6));
        }

