        /* â•â• LIVE CLOCK â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â• */
        function setupLiveClock() {
            const clockEl = document.getElementById('liveClock'),
                secsEl = document.getElementById('liveSecs'),
                dotEl = document.getElementById('liveDot'),
                labelEl = document.getElementById('liveLabel'),
                nextEl = document.getElementById('liveNext');
            if (!clockEl) return;
            const sched = [{
                opens: -1,
                closes: -1
            }, {
                opens: 480,
                lunchClose: 750,
                lunchOpen: 870,
                closes: 1080
            }, {
                opens: 480,
                lunchClose: 750,
                lunchOpen: 870,
                closes: 1080
            }, {
                opens: 480,
                lunchClose: 750,
                lunchOpen: 870,
                closes: 1080
            }, {
                opens: 480,
                lunchClose: 750,
                lunchOpen: 870,
                closes: 1080
            }, {
                opens: 480,
                lunchClose: 750,
                lunchOpen: 870,
                closes: 1080
            }, {
                opens: 480,
                closes: 720
            }];
            const fmt = m => String(Math.floor(m / 60)).padStart(2, '0') + ':' + String(m % 60).padStart(2, '0');

            function statusForDayTime(sc, total) {
                if (sc.opens === -1) return 'closed';
                if (total >= sc.opens && total < (sc.lunchClose || sc.closes)) return 'open';
                if (sc.lunchClose && total >= sc.lunchClose && total < sc.lunchOpen) return 'lunch';
                if (sc.lunchOpen && total >= sc.lunchOpen && total < sc.closes) return 'open';
                return 'closed';
            }

            function progressPercent(sc, total) {
                if (sc.opens === -1 || total < sc.opens || total > sc.closes) return 0;
                const totalMinutes = sc.closes - sc.opens - (sc.lunchClose ? (sc.lunchOpen - sc.lunchClose) : 0);
                let elapsed = total - sc.opens;
                if (sc.lunchClose && total > sc.lunchClose) elapsed -= Math.min(total - sc.lunchClose, sc.lunchOpen - sc.lunchClose);
                return Math.min(100, Math.max(0, (elapsed / totalMinutes) * 100));
            }

            function setPill(row, status) {
                if (!row) return;
                const pill = row.querySelector('.status-pill');
                if (!pill) return;
                pill.className = 'status-pill';
                if (status === 'open') {
                    pill.classList.add('open');
                    pill.innerHTML = '<span class="status-pill-dot"></span>Aperto';
                } else if (status === 'lunch') {
                    pill.classList.add('lunch');
                    pill.innerHTML = '<span class="status-pill-dot"></span>Pausa';
                } else {
                    pill.classList.add('closed-s');
                    pill.innerHTML = '<span class="status-pill-dot"></span>Chiuso';
                }
            }

            function tick() {
                const now = new Date(),
                    h = now.getHours(),
                    m = now.getMinutes(),
                    s = now.getSeconds(),
                    total = h * 60 + m,
                    day = now.getDay(),
                    sc = sched[day];
                clockEl.textContent = String(h).padStart(2, '0') + ':' + String(m).padStart(2, '0');
                secsEl.textContent = ':' + String(s).padStart(2, '0');
                const todayStatus = statusForDayTime(sc, total);
                dotEl.className = 'live-dot ' + todayStatus;
                let nextInfo = '';
                if (sc.opens !== -1) {
                    if (todayStatus === 'open') {
                        const closeAt = (sc.lunchClose && total < sc.lunchClose) ? sc.lunchClose : sc.closes;
                        nextInfo = 'Chiude alle ' + fmt(closeAt);
                    } else if (todayStatus === 'lunch') {
                        nextInfo = 'Riapre alle ' + fmt(sc.lunchOpen);
                    } else if (total < sc.opens) {
                        nextInfo = 'Apre alle ' + fmt(sc.opens);
                    }
                }
                nextEl.textContent = nextInfo;
                if (todayStatus === 'open') {
                    labelEl.textContent = 'Aperto adesso';
                    labelEl.style.color = '#4ade80';
                } else if (todayStatus === 'lunch') {
                    labelEl.textContent = 'Pausa pranzo';
                    labelEl.style.color = 'var(--gold-lt)';
                } else {
                    labelEl.textContent = 'Chiuso';
                    labelEl.style.color = '#f87171';
                }
                const rowDayMap = [{
                    id: 'row-lun',
                    dayIdx: 1
                }, {
                    id: 'row-mar',
                    dayIdx: 2
                }, {
                    id: 'row-mer',
                    dayIdx: 3
                }, {
                    id: 'row-gio',
                    dayIdx: 4
                }, {
                    id: 'row-ven',
                    dayIdx: 5
                }, {
                    id: 'row-sab',
                    dayIdx: 6
                }, {
                    id: 'row-dom',
                    dayIdx: 0
                }];
                rowDayMap.forEach(({
                    id,
                    dayIdx
                }) => {
                    const row = document.getElementById(id);
                    if (!row) return;
                    const rowSc = sched[dayIdx];
                    if (dayIdx === day) {
                        const st = statusForDayTime(rowSc, total);
                        setPill(row, st);
                        const pct = progressPercent(rowSc, total);
                        const fill = row.querySelector('.srow-progress-fill');
                        if (fill) fill.style.width = pct + '%';
                    } else {
                        if (rowSc.opens === -1) setPill(row, 'closed');
                        else setPill(row, 'closed-s');
                        const fill = row.querySelector('.srow-progress-fill');
                        if (fill) fill.style.width = '0%';
                    }
                });
            }
            tick();
            setInterval(tick, 1000);
        }

