        /* â•â• TICKER â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â• */
        function setupMouseTrailTicker() {
            const track = document.getElementById('tickerTrack');
            if (!track) return;
            const BASE_SPEED = 1.1,
                MAX_BOOST = 3.5,
                FRICTION = .92;
            let x = 0,
                boost = 0,
                lastMX = 0,
                paused = false,
                halfW = 0;

            function measureHalf() {
                halfW = track.scrollWidth / 2;
            }
            measureHalf();
            window.addEventListener('resize', measureHalf);
            document.addEventListener('mousemove', e => {
                const delta = e.clientX - lastMX;
                lastMX = e.clientX;
                boost += delta * .12;
                boost = Math.max(-MAX_BOOST, Math.min(MAX_BOOST, boost));
            });
            track.addEventListener('mouseenter', () => paused = true);
            track.addEventListener('mouseleave', () => paused = false);
            (function loop() {
                requestAnimationFrame(loop);
                if (paused) {
                    boost *= FRICTION;
                    return;
                }
                boost *= FRICTION;
                const speed = BASE_SPEED - boost;
                const clampedSpeed = Math.max(.3, Math.min(BASE_SPEED + MAX_BOOST, speed));
                x -= clampedSpeed;
                if (halfW > 0 && x <= -halfW) x += halfW;
                track.style.transform = 'translateX(' + x + 'px)';
            })();
        }

        /* â•â• LOGO HOVER SPARK â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â• */
        function setupLogoHoverSpark() {
            const canvas = document.getElementById('curCanvas'),
                ctx = canvas.getContext('2d');
            document.querySelectorAll('.lc').forEach(cell => {
                cell.addEventListener('mouseenter', () => {
                    const r = cell.getBoundingClientRect(),
                        cx = r.left + r.width / 2,
                        cy = r.top + r.height / 2;
                    for (let i = 0; i < 12; i++) {
                        const angle = (i / 12) * Math.PI * 2;
                        setTimeout(() => {
                            const len = Math.random() * 18 + 8;
                            ctx.save();
                            ctx.globalAlpha = .65;
                            ctx.strokeStyle = '#c8a84b';
                            ctx.lineWidth = 1.5;
                            ctx.shadowColor = '#c8a84b';
                            ctx.shadowBlur = 8;
                            ctx.beginPath();
                            ctx.moveTo(cx, cy);
                            ctx.lineTo(cx + Math.cos(angle) * len, cy + Math.sin(angle) * len);
                            ctx.stroke();
                            ctx.restore();
                        }, i * 12);
                    }
                });
            });
        }

